styles:
.blog-header {
      background: linear-gradient(135deg, var(--primary) 0%, #6366f1 100%);
      padding: 8rem 0 4rem;
      text-align: center;
      color: white;
    }
    .blog-header h1 {
      font-size: clamp(2rem, 5vw, 3rem);
      margin-bottom: 1.5rem;
      max-width: 900px;
      margin-left: auto;
      margin-right: auto;
    }
    .blog-meta {
      display: flex;
      justify-content: center;
      gap: 2rem;
      flex-wrap: wrap;
      font-size: 0.875rem;
      opacity: 0.9;
    }
    .blog-meta span {
      display: flex;
      align-items: center;
      gap: 0.5rem;
    }
    .blog-content {
      background: white;
      padding: 4rem 0;
    }
    .blog-content .container {
      max-width: 800px;
    }
    .blog-image {
      width: 100%;
      border-radius: var(--radius-lg);
      margin-bottom: 2rem;
      box-shadow: var(--shadow-lg);
    }
    .blog-body {
      font-size: 1.125rem;
      line-height: 1.8;
      color: var(--text-secondary);
    }
    .blog-body h2 {
      font-size: 1.75rem;
      margin: 2.5rem 0 1rem;
      color: var(--text-primary);
    }
    .blog-body h3 {
      font-size: 1.375rem;
      margin: 2rem 0 1rem;
      color: var(--text-primary);
    }
    .blog-body p {
      margin-bottom: 1.5rem;
    }
    .blog-body ul, .blog-body ol {
      margin-bottom: 1.5rem;
      padding-left: 1.5rem;
    }
    .blog-body li {
      margin-bottom: 0.75rem;
    }
    .blog-body blockquote {
      border-left: 4px solid var(--primary);
      padding: 1.5rem;
      margin: 2rem 0;
      background: var(--bg-secondary);
      border-radius: 0 var(--radius-lg) var(--radius-lg) 0;
      font-style: italic;
    }
    .back-link {
      display: inline-flex;
      align-items: center;
      gap: 0.5rem;
      color: white;
      opacity: 0.9;
      font-weight: 500;
      margin-bottom: 2rem;
    }
    .back-link:hover {
      opacity: 1;
      text-decoration: underline;
    }
    @media (max-width: 768px) {
      .blog-header {
        padding: 6rem 0 3rem;
      }
      .blog-content {
        padding: 3rem 0;
      }
      .blog-meta {
        gap: 1rem;
      }
    }
